// Normalise name, calculate alcolOrdine and ordine_str for the current order
const body    = $input.first().json.body;
const nomeRaw = (body.nome || 'Anonimo').trim();
const nome    = nomeRaw.charAt(0).toUpperCase() + nomeRaw.slice(1).toLowerCase();
const orario  = body.orario || new Date().toLocaleString('it-IT');
const ordine  = body.ordine || [];
const today   = new Date().toISOString().slice(0, 10);

const alcolOrdine = ordine.reduce((s, i) => s + (i.alcol_grammi || 0) * (i.quantita || 1), 0);

const ordine_str = ordine
  .map(i => {
    let s = i.quantita + 'x ' + i.nome;
    if (i.dettaglio) s += ' ' + i.dettaglio;
    return s;
  })
  .join(', ');

return [{ json: { nome, orario, ordine, ordine_str, alcolOrdine: Math.round(alcolOrdine * 10) / 10, today } }];

// Calculate cumulative BAC reading today's rows from the DataTable
// rows = all orders for this person today (including the one just inserted)
const rows      = $input.all().map(i => i.json);
const nome      = $('Prepare Order').item.json.nome;
const orario    = $('Prepare Order').item.json.orario;
const ordine_str = $('Prepare Order').item.json.ordine_str;

const totalAlcol = Math.round(rows.reduce((s, r) => s + (r.alcol_grammi || 0), 0) * 10) / 10;
const nOrdini    = rows.length;
const bac        = totalAlcol > 0 ? totalAlcol / (70 * 0.68) : 0;
const bacStr     = bac.toFixed(2);

const E_OK    = String.fromCodePoint(0x1F7E2);
const E_WARN  = String.fromCodePoint(0x1F7E1);
const E_OVER  = String.fromCodePoint(0x1F534);
const E_NONE  = String.fromCodePoint(0x2B1C);
const E_LIST  = String.fromCodePoint(0x1F4CB);
const E_CLOCK = String.fromCodePoint(0x1F552);
const E_DRINK = String.fromCodePoint(0x1F378);
const E_WATER = String.fromCodePoint(0x1F964);
const E_TIME  = String.fromCodePoint(0x1F550);

let bacLevel;
if      (bac === 0)  bacLevel = E_NONE;
else if (bac < 0.2)  bacLevel = E_OK;
else if (bac < 0.5)  bacLevel = E_WARN;
else                  bacLevel = E_OVER;

// Previous orders = all rows except the last (the one just inserted)
const prevOrders = rows.slice(0, -1);
const storStr = prevOrders.length > 0
  ? '\n' + E_LIST + ' Gia ordinato oggi (' + prevOrders.length + ' ordini):\n'
    + prevOrders.map(r => '  - ' + r.item + '  ' + E_CLOCK + ' ' + r.orario).join('\n')
  : '';

const bacRow = totalAlcol > 0
  ? '\n' + E_DRINK + ' BAC ~' + bacStr + ' g/L  ' + bacLevel
  : '\n' + E_WATER + ' nessun alcolico';

const messaggio = nome + ': ' + ordine_str
  + '\n' + E_TIME + ' ' + orario
  + storStr
  + bacRow;

return [{
  json: {
    nome,
    orario,
    ordine_str,
    messaggio,
    bac:        bacStr,
    bacLevel,
    totalAlcol,
    alcolOrdine: $('Prepare Order').item.json.alcolOrdine,
    nOrdini,
    today: $('Prepare Order').item.json.today
  }
}];
